// Pico LED Light Show
// 6 LEDs on GP10-GP15 cycle through chase, bounce, and sparkle patterns.

#include <Arduino.h>

const int NUM_LEDS = 6;
const int LED_PINS[NUM_LEDS] = {10, 11, 12, 13, 14, 15};

void allOff() {
  for (int i = 0; i < NUM_LEDS; i++)
    digitalWrite(LED_PINS[i], LOW);
}

void allOn() {
  for (int i = 0; i < NUM_LEDS; i++)
    digitalWrite(LED_PINS[i], HIGH);
}

// Pattern 1: Chase left to right
void chase(int speed) {
  Serial.println("Pattern: Chase");
  for (int repeat = 0; repeat < 3; repeat++) {
    for (int i = 0; i < NUM_LEDS; i++) {
      allOff();
      digitalWrite(LED_PINS[i], HIGH);
      delay(speed);
    }
  }
}

// Pattern 2: Bounce (Knight Rider)
void bounce(int speed) {
  Serial.println("Pattern: Bounce");
  for (int repeat = 0; repeat < 3; repeat++) {
    for (int i = 0; i < NUM_LEDS; i++) {
      allOff();
      digitalWrite(LED_PINS[i], HIGH);
      delay(speed);
    }
    for (int i = NUM_LEDS - 2; i > 0; i--) {
      allOff();
      digitalWrite(LED_PINS[i], HIGH);
      delay(speed);
    }
  }
}

// Pattern 3: Random sparkle
void sparkle(int speed, int count) {
  Serial.println("Pattern: Sparkle");
  for (int i = 0; i < count; i++) {
    allOff();
    int led = random(NUM_LEDS);
    digitalWrite(LED_PINS[led], HIGH);
    delay(speed);
  }
}

// Pattern 4: Stack fill
void stackFill(int speed) {
  Serial.println("Pattern: Stack Fill");
  for (int fill = 0; fill < NUM_LEDS; fill++) {
    for (int i = 0; i < NUM_LEDS - fill; i++) {
      allOff();
      // Keep already-stacked LEDs on
      for (int s = NUM_LEDS - 1; s >= NUM_LEDS - fill; s--)
        digitalWrite(LED_PINS[s], HIGH);
      digitalWrite(LED_PINS[i], HIGH);
      delay(speed);
    }
  }
  delay(500);
}

void setup() {
  for (int i = 0; i < NUM_LEDS; i++)
    pinMode(LED_PINS[i], OUTPUT);

  Serial.begin(115200);
  delay(100);
  Serial.println("Pico LED Light Show started!");
  randomSeed(analogRead(26));  // seed from ADC noise
}

void loop() {
  chase(100);
  delay(300);

  bounce(80);
  delay(300);

  sparkle(60, 30);
  delay(300);

  stackFill(80);
  delay(300);

  // Flash all for finale
  for (int i = 0; i < 5; i++) {
    allOn();  delay(150);
    allOff(); delay(150);
  }
  Serial.println("--- Show complete, restarting ---");
  delay(1000);
}
